#include "crypto_asm_hidden.h"
// linker define mladder

/* Assembly for Montgomery ladder */

	.p2align 4
	ASM_HIDDEN _CRYPTO_SHARED_NAMESPACE(mladder)
	.globl _CRYPTO_SHARED_NAMESPACE(mladder)
	ASM_HIDDEN CRYPTO_SHARED_NAMESPACE(mladder)
	.globl CRYPTO_SHARED_NAMESPACE(mladder)

_CRYPTO_SHARED_NAMESPACE(mladder):
CRYPTO_SHARED_NAMESPACE(mladder):

	sub	sp, sp, #624
	stp	x19, x20, [sp, #0]
	stp	x21, x22, [sp, #16]
	stp	x23, x24, [sp, #32]
	stp	x25, x26, [sp, #48]
	stp	x27, x28, [sp, #64]
	stp	x29, x30, [sp, #80]	
	stp	x0, x2, [sp, #96]
	
	// clamp scalar
	ldr	x3, [x2, #0]
	and	x3, x3, #0xfffffffffffffff8
	str	x3, [x2, #0]
	ldr	x4, [x2, #24]
	orr	x4, x4, #0x4000000000000000
	str	x4, [x2, #24]	

	// XP
	ldp	x4, x5, [x1, #0]	
	ldp	x6, x7, [x1, #16]

	// X1 ← XP
	and	w8, w4, #0x3ffffff
	ubfx	x9, x4, #26, #25
	
	lsr	x10, x4, #51
	orr	w10, w10, w5, lsl #13
	and	w10, w10, #0x3ffffff
	ubfx	x11, x5, #13, #25
	
	lsr	x12, x5, #38
	and	w13, w6, #0x1ffffff	

	ubfx	x14, x6, #25, #26
	lsr	x15, x6, #51
	orr	w15, w15, w7, lsl #13
	and	w15, w15, #0x1ffffff
		
	ubfx	x16, x7, #12, #26
	ubfx	x17, x7, #38, #25
	
	// store X1
	add	x0, sp, #144
	stp	 w8,  w9, [x0, #0]
	stp	w10, w11, [x0, #8]
	stp	w12, w13, [x0, #16]
	stp	w14, w15, [x0, #24]
	stp	w16, w17, [x0, #32]
	
	// X3 ← X1
	add	x0, sp, #264
	stp	 w8,  w9, [x0, #0]
	stp	w10, w11, [x0, #8]
	stp	w12, w13, [x0, #16]
	stp	w14, w15, [x0, #24]
	stp	w16, w17, [x0, #32]	
	
	// X2 ← 1
	mov	x10, #1
	stp	x10, xzr, [sp, #184]
	stp	xzr, xzr, [sp, #200]
	str	xzr, [sp, 216]
	
	// Z2 ← 0	
	stp	xzr, xzr, [sp, #224]
	stp	xzr, xzr, [sp, #240]
	str	xzr, [sp, #256]	
	
	// Z3 ← 1
	stp	x10, xzr, [sp, #304]
	stp	xzr, xzr, [sp, #320]
	str	xzr, [sp, #336]		
	
	mov	w30, #19
	
	movz	x1, #0xffda 
	movk	x1, #0x07ff, lsl 16
	movk	x1, #0xfffe, lsl 32
	movk	x1, #0x03ff, lsl 48
	
