	movk	x2, #0x07ff, lsl 16
	movk	x2, #0xfffe, lsl 32
	movk	x2, #0x03ff, lsl 48	
	
	stp	x1, x2, [sp, #128]
		
        // pre-process for the bit n[254] = 1 	
	
	// T2 = 2X3
	ldp	x10, x12, [sp, #264]
	ldp	x14, x16, [sp, #280]
	ldr	x18, [sp, #296]
		
