        add	x22, x12, x12
        add	x24, x14, x14
        add	x26, x16, x16
        add	x28, x18, x18                        
                
	stp	x20, x22, [sp, #384]
	stp	x24, x26, [sp, #400]
	str	x28, [sp, #416]
	
